<?php
namespace App\Modules\Hr\Asset\Actions;
use App\Modules\Hr\Asset\Enums\AssetStatus; use App\Modules\Hr\Asset\Models\HrAsset; use App\Modules\Hr\Asset\Models\HrAssetEvent; use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext;
class ChangeAssetStatusAction { public function __construct(private HrAuditService $audit){} public function execute(HrAsset $asset,AssetStatus $status,string $note):HrAsset{abort_unless(auth()->user()?->hasHrPermission('hr.assets.manage'),403);abort_unless($asset->legal_entity_id===app(TenantContext::class)->getId(),404);abort_if($asset->status===AssetStatus::Assigned,422,'Aktif zimmet iade edilmeden durum değiştirilemez.');abort_if(blank($note),422,'Durum değişikliği gerekçesi zorunludur.');$from=$asset->status;$asset->update(['status'=>$status,'updated_by'=>auth()->id()]);HrAssetEvent::create(['legal_entity_id'=>$asset->legal_entity_id,'asset_id'=>$asset->id,'event_type'=>'status_changed','from_status'=>$from->value,'to_status'=>$status->value,'note'=>trim($note),'acted_by'=>auth()->id(),'created_at'=>now()]);$this->audit->log('asset_status_changed',$asset,['status'=>$from->value],['status'=>$status->value]);return $asset->fresh();} }
